# Guard clause pattern — fail fast before doing expensive work
def process_message(msg: str) -> str:
    if not msg:
        return ""
    if len(msg) > 4096:
        raise ValueError(f"Message too long: {len(msg)} chars")

    # Main logic only reached with a valid message
    return msg.strip().lower()


