import time

# Agent run-loop skeleton
def run_agent(agent, max_steps: int = 20) -> str:
    step = 0
    while step < max_steps:
        action = agent.plan()
        if action.is_terminal:
            return action.result
        observation = agent.act(action)
        agent.observe(observation)
        step += 1
    raise RuntimeError("Agent exceeded max steps")


