from dataclasses import dataclass
from typing import Callable

@dataclass
class Action:
    kind: str       # "search", "calculate", "answer"
    payload: str

@dataclass
class Observation:
    result: str

# Stub tools
def search(query: str) -> str:
    return f"[search result for '{query}']: ..."

def calculate(expr: str) -> str:
    try:
        return str(eval(expr, {"__builtins__": {}}))  # noqa: S307
    except Exception as e:
        return f"Error: {e}"

TOOLS: dict[str, Callable[[str], str]] = {
    "search": search,
    "calculate": calculate,
}

def agent_loop(plan_fn: Callable[[list], Action], max_steps: int = 10) -> str:
    """
    Run a ReAct-style agent.
    plan_fn receives the observation history and returns the next Action.
    """
    history: list[Observation] = []
    step = 0

    while step < max_steps:
        action = plan_fn(history)

        if action.kind == "answer":
            return action.payload          # terminal action — break out cleanly

        if action.kind not in TOOLS:
            raise ValueError(f"Unknown action kind: {action.kind!r}")

        tool_fn = TOOLS[action.kind]
        raw_result = tool_fn(action.payload)
        obs = Observation(result=raw_result)
        history.append(obs)
        step += 1

    raise RuntimeError(f"Agent did not finish within {max_steps} steps")


