# O(n * m) — inner loop scans the whole list for each item
def has_common_slow(a: list, b: list) -> bool:
    for x in a:
        for y in b:
            if x == y:
                return True
    return False

# O(n + m) — convert one list to a set, then do O(1) lookups
def has_common_fast(a: list, b: list) -> bool:
    b_set = set(b)
    for x in a:
        if x in b_set:
            return True
    return False

import signal

class TimeoutError(Exception):
    pass

def _handler(signum, frame):
    raise TimeoutError("Agent loop timed out")

def run_with_timeout(fn, seconds: int = 30):
    signal.signal(signal.SIGALRM, _handler)
    signal.alarm(seconds)
    try:
        return fn()
    finally:
        signal.alarm(0)   # cancel alarm
